public int[] tenRun(int[] nums) {
    if (nums.length == 0) return nums;

    int multiple = 0;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            multiple = nums[i];
        } else if (multiple != 0) {
            nums[i] = multiple;
        }
    }

    return nums;
}

